import { test, expect } from "bun:test";
import { isEven } from "./iseven";

test("AC-DST-39.1: returns true for even integers", () => {
  const evenFixtures = [0, 2, -4];
  for (const n of evenFixtures) {
    expect(isEven(n)).toBe(true);
  }
});

test("AC-DST-39.2: returns false for odd integers", () => {
  const oddFixtures = [1, -3, 7];
  for (const n of oddFixtures) {
    expect(isEven(n)).toBe(false);
  }
});

